from decimal import Decimal, ROUND_HALF_UP
from typing import Sequence

def even_split(
    pool_cost_usd: Decimal,
    teams: Sequence[str],
) -> dict[str, Decimal]:
    if not teams:
        return {}
    share = (pool_cost_usd / len(teams)).quantize(
        Decimal("0.01"), rounding=ROUND_HALF_UP
    )
    # Distribute any rounding remainder to the first team
    remainder = pool_cost_usd - share * len(teams)
    result = {team: share for team in teams}
    result[teams[0]] += remainder
    return result

# Example
pool   = Decimal("18000.00")
teams  = ["payments", "risk", "cx"]
shares = even_split(pool, teams)
