from collections import defaultdict
from decimal import Decimal, ROUND_HALF_UP

def token_weighted_split(
    pool_cost_usd: Decimal,
    ledger_rows: list[dict],    # from token cost ledger
    period_month: str,           # "2025-06"
) -> dict[str, Decimal]:
    token_by_team: dict[str, int] = defaultdict(int)
    for row in ledger_rows:
        if (
            row["timestamp_utc"][:7] == period_month
            and row["env"] == "production"
        ):
            team = row.get("team", "untagged")
            token_by_team[team] += (
                row["prompt_tokens"] + row["completion_tokens"]
            )
    total_tokens = sum(token_by_team.values())
    if total_tokens == 0:
        # Fall back to even split if no token data
        return even_split(pool_cost_usd, list(token_by_team) or ["platform"])

    shares: dict[str, Decimal] = {}
    allocated = Decimal("0")
    teams = list(token_by_team)
    for i, team in enumerate(teams):
        fraction = Decimal(token_by_team[team]) / Decimal(total_tokens)
        if i < len(teams) - 1:
            share = (pool_cost_usd * fraction).quantize(
                Decimal("0.01"), rounding=ROUND_HALF_UP
            )
        else:
            share = pool_cost_usd - allocated  # absorb rounding
        shares[team] = share
        allocated   += share
    return shares

from decimal import Decimal
from enum import Enum

class PlatformTier(Enum):
    BASIC      = "basic"       # Small team, ≤500K tokens/month
    STANDARD   = "standard"    # Mid-size team, 500K–2M tokens/month
    ENTERPRISE = "enterprise"  # Large team, >2M tokens/month

# Fixed monthly platform fee per tier (USD)
TIER_FEE: dict[PlatformTier, Decimal] = {
    PlatformTier.BASIC:      Decimal("3000"),
    PlatformTier.STANDARD:   Decimal("6000"),
    PlatformTier.ENTERPRISE: Decimal("9000"),
}

def tiered_subscription_split(
    team_tiers: dict[str, PlatformTier],
) -> dict[str, Decimal]:
    """Returns {team: monthly_platform_fee_usd}."""
    return {team: TIER_FEE[tier] for team, tier in team_tiers.items()}

# Tier assignment is reviewed quarterly based on trailing 3-month avg token volume
def assign_tier(avg_monthly_tokens: int) -> PlatformTier:
    if avg_monthly_tokens > 2_000_000:
        return PlatformTier.ENTERPRISE
    if avg_monthly_tokens > 500_000:
        return PlatformTier.STANDARD
    return PlatformTier.BASIC

from dataclasses import dataclass
from decimal import Decimal

@dataclass
class PoolSpendAnomaly:
    pool_item:      str
    current_cost:   Decimal
    baseline_cost:  Decimal   # 3-month rolling average
    pct_deviation:  float

    @property
    def is_anomalous(self) -> bool:
        return self.pct_deviation > 0.25

def detect_pool_anomalies(
    pool_items: list[PoolItem],
    history: dict[str, list[Decimal]],  # {item_name: [cost_m-3, cost_m-2, cost_m-1]}
) -> list[PoolSpendAnomaly]:
    anomalies = []
    for item in pool_items:
        past = history.get(item.name, [])
        if len(past) < 2:
            continue  # not enough history
        baseline = sum(past) / len(past)
        if baseline == 0:
            continue
        deviation = float((item.cost_usd - baseline) / baseline)
        anomalies.append(PoolSpendAnomaly(
            pool_item     = item.name,
            current_cost  = item.cost_usd,
            baseline_cost = baseline,
            pct_deviation = deviation,
        ))
    return [a for a in anomalies if a.is_anomalous]

