import pytest
from decimal import Decimal

def test_even_split_sums_to_pool():
    pool   = Decimal("18000.00")
    teams  = ["payments", "risk", "cx"]
    shares = even_split(pool, teams)
    assert sum(shares.values()) == pool

def test_even_split_single_team():
    pool   = Decimal("500.00")
    shares = even_split(pool, ["only-team"])
    assert shares["only-team"] == pool

def test_even_split_empty_teams():
    shares = even_split(Decimal("1000"), [])
    assert shares == {}

def test_token_weighted_falls_back_to_even_with_no_data():
    pool   = Decimal("6000.00")
    shares = token_weighted_split(pool, [], "2025-06")
    # Falls back: single "platform" key or empty — just must not raise
    assert sum(shares.values()) == pool or shares == {}

