def test_tiered_subscription_returns_fixed_fee():
    tiers  = {"teamA": PlatformTier.ENTERPRISE, "teamB": PlatformTier.BASIC}
    shares = tiered_subscription_split(tiers)
    assert shares["teamA"] == TIER_FEE[PlatformTier.ENTERPRISE]
    assert shares["teamB"] == TIER_FEE[PlatformTier.BASIC]
